    if (typeof window !== 'undefined') {
      const savedTheme = localStorage.getItem('cofound_theme');
      if (savedTheme === 'light' || savedTheme === 'dark') {
        return savedTheme;
      }
      if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
