    setMessages(threadMessages);
  }, [selectedThread]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, activeChannel]); 

  // Close context menu on click outside or scroll
  useEffect(() => {
    const closeMenu = () => setContextMenu(prev => ({ ...prev, visible: false }));
    window.addEventListener('click', closeMenu);
    window.addEventListener('scroll', closeMenu, true);
    return () => {
      window.removeEventListener('click', closeMenu);
      window.removeEventListener('scroll', closeMenu, true);
    };
  }, []);

  const sendMessage = () => {
    if (!inputText.trim()) return;
    setMessages(prev => [...prev, { 
      id: prev.length + 100, 
      sender: "me", 
      text: inputText, 
      time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
    }]);
    setInputText("");
  };

  const handleCreateSpace = () => {
    if(!newSpaceName.trim()) return;
    const newSpace: Space = {
      id: Date.now(),
      name: newSpaceName,
      description: "New workspace",
      icon: newSpaceName[0].toUpperCase(),
      color: "bg-cofound-blue",
      members: 1,
      channels: [
        { id: `c-${Date.now()}-1`, name: "general", type: "CHAT" },
        { id: `c-${Date.now()}-2`, name: "tasks", type: "TASKS" }
      ]
    };
    setSpaces([...spaces, newSpace]);
    setNewSpaceName("");
    setShowNewSpaceInput(false);
    setActiveSpaceId(newSpace.id);
    setViewMode('SPACE');
    setShowMobileChat(true);
  };

  const handleThreadSelect = (thread: ChatThread) => {
    setViewMode('DM');
    setSelectedThread(thread);
    setShowMobileChat(true);
  };

  const handleSpaceSelect = (space: Space) => {
    setViewMode('SPACE');
    setActiveSpaceId(space.id);
    setActiveChannel(space.channels[0]);
    setShowMobileChat(true);
  };

  // --- CONTEXT MENU HANDLERS ---

  const handleContextMenu = (e: React.MouseEvent, msgId: number) => {
    e.preventDefault();
    setContextMenu({
      visible: true,
      x: e.clientX,
      y: e.clientY,
      messageId: msgId,
      isMobile: false
    });
  };

  const handleTouchStart = (msgId: number, e: React.TouchEvent) => {
    const touch = e.touches[0];
    const clientX = touch.clientX;
    const clientY = touch.clientY;

    longPressTimer.current = setTimeout(() => {
      // Vibrate if supported
      if (navigator.vibrate) navigator.vibrate(50);

      setContextMenu({
        visible: true,
        x: clientX,
        y: clientY,
        messageId: msgId,
        isMobile: true
      });
    }, 500); // 500ms long press
  };

  const handleTouchEnd = () => {
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }
  };

  const handleMenuAction = (action: string) => {
    console.log(`Action: ${action} on message ${contextMenu.messageId}`);
    setContextMenu(prev => ({ ...prev, visible: false }));
    // Here you would implement the actual logic (copy, delete, etc.)
  };

  const renderContextMenu = () => {
    if (!contextMenu.visible) return null;

    // Calculate position adjustments to keep menu on screen
    const menuWidth = 220; // Approx width
    const menuHeight = 250; // Approx height

    let left = contextMenu.x;
    let top = contextMenu.y;

    // Adjust horizontal position
    if (left + menuWidth > window.innerWidth) {
      left = window.innerWidth - menuWidth - 10;
    }

    // Adjust vertical position
    if (top + menuHeight > window.innerHeight) {
      top = window.innerHeight - menuHeight - 10;
    }

    // For mobile, we center it visually or use bottom sheet style, but simple positioning works for now
    // If mobile, we might want to offset it slightly up so finger doesn't cover it
    if (contextMenu.isMobile) {
       top -= 20; 
    }

    return (
      <div 
        className="fixed z-50 bg-white dark:bg-cofound-darkCard border border-cofound-grey/50 dark:border-white/10 rounded-xl shadow-2xl animate-fade-in overflow-hidden w-56 backdrop-blur-sm bg-opacity-95 dark:bg-opacity-95"
        style={{ left, top }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Emoji Reactions */}
        <div className="flex justify-between items-center p-2 bg-cofound-bg/50 dark:bg-white/5 border-b border-cofound-grey/50 dark:border-white/10">
           {['😊', '😢', '😂', '❤️', '😡'].map(emoji => (
             <button 
               key={emoji}
               onClick={() => handleMenuAction(`react-${emoji}`)}
               className="w-8 h-8 flex items-center justify-center text-lg hover:bg-white dark:hover:bg-white/10 rounded-full transition-transform hover:scale-125"
             >
               {emoji}
             </button>
           ))}
        </div>

        {/* Actions */}
        <div className="py-1">
           <button onClick={() => handleMenuAction('copy')} className="w-full text-left px-4 py-2.5 hover:bg-cofound-bg dark:hover:bg-white/5 flex items-center gap-3 text-sm font-medium text-cofound-text dark:text-white transition-colors">
              <Copy size={16} className="text-cofound-textLight dark:text-cofound-textDark/60" /> Copy Message
           </button>
           <button onClick={() => handleMenuAction('forward')} className="w-full text-left px-4 py-2.5 hover:bg-cofound-bg dark:hover:bg-white/5 flex items-center gap-3 text-sm font-medium text-cofound-text dark:text-white transition-colors">
              <CornerUpRight size={16} className="text-cofound-textLight dark:text-cofound-textDark/60" /> Forward
           </button>
           <div className="h-px bg-cofound-grey/50 dark:bg-white/10 my-1 mx-2"></div>
           <button onClick={() => handleMenuAction('report')} className="w-full text-left px-4 py-2.5 hover:bg-cofound-bg dark:hover:bg-white/5 flex items-center gap-3 text-sm font-medium text-cofound-text dark:text-white transition-colors">
              <Flag size={16} className="text-cofound-textLight dark:text-cofound-textDark/60" /> Report
           </button>
           <button onClick={() => handleMenuAction('delete')} className="w-full text-left px-4 py-2.5 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-3 text-sm font-medium text-red-600 dark:text-red-400 transition-colors">
              <Trash2 size={16} /> Delete
           </button>
        </div>
      </div>
    );
  };

  const renderChannelContent = () => {
    switch (activeChannel.type) {
      case 'TASKS':
        return (
          <div className="p-6 h-full overflow-y-auto pb-24 md:pb-6">
             <div className="flex justify-between items-center mb-6">
                <h3 className="font-bold text-lg text-cofound-text dark:text-white">Active Tasks</h3>
                <Button size="sm" variant="outline"><Plus size={16}/> Add Task</Button>
             </div>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {['TODO', 'IN_PROGRESS', 'DONE'].map(status => (
                   <div key={status} className="space-y-3">
                      <div className="flex items-center justify-between text-xs font-bold text-cofound-textLight dark:text-cofound-textDark/60 uppercase tracking-widest mb-2">
                         {status.replace('_', ' ')}
                         <span className="bg-cofound-grey dark:bg-white/10 px-2 py-0.5 rounded-full">{MOCK_TASKS.filter(t => t.status === status).length}</span>
                      </div>
                      {MOCK_TASKS.filter(t => t.status === status).map(task => (
                         <div key={task.id} className="bg-white dark:bg-cofound-darkCard p-3 rounded-xl border border-cofound-grey dark:border-white/10 shadow-sm hover:shadow-md transition-shadow cursor-pointer group">
                            <div className="flex justify-between items-start mb-2">
                               <span className={`text-[10px] px-1.5 py-0.5 rounded font-bold ${task.tag === 'Backend' ? 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300' : 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300'}`}>{task.tag}</span>
                               <MoreHorizontal size={14} className="text-cofound-textLight dark:text-cofound-textDark/40 opacity-0 group-hover:opacity-100 transition-opacity"/>
                            </div>
                            <p className="text-sm font-medium text-cofound-text dark:text-white mb-3">{task.title}</p>
                            <div className="flex items-center justify-between">
                               <Avatar initials={task.assignee} size="xs" />
                               <div className="text-[10px] text-cofound-textLight dark:text-cofound-textDark/50">Oct 24</div>
                            </div>
                         </div>
                      ))}
                      <button className="w-full py-2 border border-dashed border-cofound-grey dark:border-white/10 rounded-xl text-xs font-bold text-cofound-textLight dark:text-cofound-textDark/50 hover:bg-cofound-bg dark:hover:bg-white/5 transition-colors">
                         + New
                      </button>
                   </div>
                ))}
             </div>
          </div>
        );
      case 'NOTES':
        return (
          <div className="p-8 h-full flex flex-col items-center justify-center text-center opacity-60">
             <FileText size={48} className="mb-4 text-cofound-textLight dark:text-cofound-textDark/40" />
             <h3 className="font-bold text-lg text-cofound-text dark:text-white">Team Notes</h3>
             <p className="text-sm max-w-xs text-cofound-textLight dark:text-cofound-textDark/60 mt-1">Shared documents and meeting minutes live here.</p>
             <Button variant="primary" size="sm" className="mt-4">Create Doc</Button>
          </div>
        );
      case 'FILES':
        return (
          <div className="p-6 h-full overflow-y-auto">
             <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {[1,2,3,4].map(i => (
                   <div key={i} className="aspect-square bg-white dark:bg-cofound-darkCard rounded-xl border border-cofound-grey dark:border-white/10 flex flex-col items-center justify-center p-4 hover:border-cofound-blue/50 cursor-pointer transition-colors">
                      <Folder size={32} className="text-cofound-blue dark:text-cofound-sky mb-2 fill-current opacity-20" />
                      <span className="text-sm font-bold text-cofound-text dark:text-white truncate w-full text-center">Design_Assets_v{i}.zip</span>
                      <span className="text-xs text-cofound-textLight dark:text-cofound-textDark/50 mt-1">2.4 MB</span>
                   </div>
                ))}
             </div>
          </div>
        );
      case 'MEMBERS':
        return (
           <div className="p-6">
              <h3 className="font-bold text-lg mb-4 text-cofound-text dark:text-white">Space Members ({activeSpace.members})</h3>
              <div className="space-y-2">
                 {SQUAD_SUGGESTIONS.slice(0, activeSpace.members).map(member => (
                    <div key={member.id} className="flex items-center justify-between p-3 bg-white dark:bg-cofound-darkCard rounded-xl border border-cofound-grey dark:border-white/10">
                       <div className="flex items-center gap-3">
                          <Avatar initials={member.name.substring(0,2)} size="md" />
                          <div>
                             <div className="font-bold text-sm text-cofound-text dark:text-white">{member.name}</div>
                             <div className="text-xs text-cofound-textLight dark:text-cofound-textDark/60">{member.role}</div>
                          </div>
                       </div>
                       <Button variant="ghost" size="sm">Message</Button>
                    </div>
                 ))}
              </div>
           </div>
        );
      case 'CHAT':
      default:
        // Reuse the chat layout for consistency
        return (
          <div className="flex flex-col h-full bg-cofound-bg/10 dark:bg-black/20">
             <div className="flex-1 p-4 md:p-6 overflow-y-auto space-y-4">
                <div className="flex justify-center pb-4">
                   <span className="text-xs font-bold text-cofound-textLight dark:text-cofound-textDark/40 uppercase tracking-widest bg-cofound-bg dark:bg-white/5 px-3 py-1 rounded-full"># {activeChannel.name} history</span>
                </div>
                {messages.map(msg => (
                  <div key={msg.id} className={`flex ${msg.sender === 'me' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[85%] md:max-w-[70%] ${msg.sender === 'me' ? 'items-end' : 'items-start'} flex flex-col`}>
                        <div 
                            onContextMenu={(e) => handleContextMenu(e, msg.id)}
                            onTouchStart={(e) => handleTouchStart(msg.id, e)}
                            onTouchEnd={handleTouchEnd}
                            onTouchMove={handleTouchEnd}
                            className={`px-4 py-2.5 rounded-2xl text-sm leading-relaxed shadow-sm relative group cursor-pointer transition-transform active:scale-[0.98] ${
                            msg.sender === 'me' 
                              ? 'bg-cofound-blue text-white rounded-br-none' 
                              : 'bg-white dark:bg-cofound-darkCard border border-cofound-nav dark:border-white/10 text-cofound-text dark:text-cofound-textDark rounded-bl-none'
                        }`}>
                            {msg.text}
                        </div>
                        <span className="text-[10px] text-cofound-textLight dark:text-cofound-textDark/40 mt-1 px-1 opacity-70">{msg.time}</span>
                      </div>
                  </div>
                ))}
                <div ref={messagesEndRef} />
             </div>
             {/* Input Area */}
             <div className="p-3 md:p-4 bg-white dark:bg-cofound-darkCard border-t border-cofound-nav dark:border-white/10 shrink-0 pb-4 md:pb-4">
                <div className="flex items-end gap-2">
                    <button className="p-2.5 text-cofound-textLight dark:text-cofound-textDark/60 hover:text-cofound-blue hover:bg-blue-50 dark:hover:bg-white/5 rounded-full transition-colors mb-0.5"><Plus size={20} /></button>
                    <div className="flex-1 bg-cofound-bg dark:bg-white/5 rounded-2xl p-2 flex items-center gap-2 border border-transparent focus-within:border-cofound-blue/30 focus-within:bg-white dark:focus-within:bg-black/20 transition-all">
                      <input 
                          type="text"
                          value={inputText}
                          onChange={(e) => setInputText(e.target.value)}
                          onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), sendMessage())}
                          placeholder={`Message #${activeChannel.name}`}
                          className="flex-1 bg-transparent border-none outline-none text-sm text-cofound-text dark:text-white placeholder:text-cofound-textLight/70 dark:placeholder:text-white/30 px-2"
                      />
                      <button className="p-1.5 text-cofound-textLight dark:text-cofound-textDark/50 hover:text-cofound-blue transition-colors"><Paperclip size={18} /></button>
                    </div>
                    <Button 
                      onClick={sendMessage}
                      size="md"
                      variant={inputText.trim() ? "primary" : "secondary"}
                      className={`!p-2.5 rounded-full mb-0.5 transition-all`}
                      disabled={!inputText.trim()}
                    >
                      <Send size={18} className={inputText.trim() ? "ml-0.5" : ""} />
                    </Button>
                </div>
             </div>
          </div>
        );
    }
  };

  return (
    <Card className="flex-1 md:h-[calc(100vh-120px)] flex flex-row !p-0 overflow-hidden shadow-lg border-cofound-nav dark:border-white/10 border-0 rounded-none md:rounded-2xl h-full">
      {renderContextMenu()}

      {/* 1. UNIFIED SIDEBAR (Spaces + DMs) */}
      <div className={`w-full md:w-80 border-r border-cofound-nav dark:border-white/10 flex flex-col bg-white dark:bg-cofound-darkCard ${showMobileChat ? 'hidden md:flex' : 'flex'}`}>

        {/* Search Header */}
        <div className="p-4 border-b border-cofound-nav dark:border-white/10 bg-cofound-bg/30 dark:bg-white/5 space-y-3">
           <div className="flex justify-between items-center">
              <h2 className="font-bold text-lg text-cofound-text dark:text-white">Comms</h2>
              <button className="p-1.5 hover:bg-cofound-grey dark:hover:bg-white/10 rounded-full transition-colors text-cofound-textLight dark:text-cofound-textDark/60"><MoreHorizontal size={18}/></button>
           </div>
           <div className="relative">
              <Search className="absolute left-3 top-2.5 text-cofound-textLight dark:text-cofound-textDark/50" size={14} />
              <input type="text" placeholder="Jump to..." className="w-full bg-cofound-bg dark:bg-white/5 pl-9 pr-3 py-2 rounded-lg text-sm outline-none focus:ring-1 focus:ring-cofound-blue dark:text-white transition-all" />
           </div>
        </div>

        <div className="flex-1 overflow-y-auto no-scrollbar">

           {/* SPACES SECTION */}
           <div className="pt-4 pb-2">
              <div className="px-4 flex justify-between items-center mb-2 group">
                 <span className="text-xs font-bold text-cofound-textLight dark:text-cofound-textDark/50 uppercase tracking-widest">My Spaces</span>
                 <button onClick={() => setShowNewSpaceInput(!showNewSpaceInput)} className="text-cofound-textLight dark:text-cofound-textDark/50 hover:text-cofound-blue"><Plus size={14} /></button>
              </div>

              {showNewSpaceInput && (
                 <div className="px-4 mb-2 animate-fade-in">
                    <input 
                      autoFocus
                      type="text" 
                      placeholder="Space name..." 
                      className="w-full text-sm bg-cofound-bg dark:bg-white/5 px-2 py-1.5 rounded border border-cofound-blue/30 outline-none text-cofound-text dark:text-white"
                      value={newSpaceName}
                      onChange={(e) => setNewSpaceName(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && handleCreateSpace()}
                    />
                 </div>
              )}

              {spaces.map(space => (
                 <div 
                    key={space.id} 
                    onClick={() => handleSpaceSelect(space)}
                    className={`px-4 py-2 mx-2 rounded-lg cursor-pointer flex items-center gap-3 transition-colors ${viewMode === 'SPACE' && activeSpaceId === space.id ? 'bg-blue-50/50 dark:bg-white/10 text-cofound-text dark:text-white' : 'text-cofound-textLight dark:text-cofound-textDark/70 hover:bg-cofound-bg dark:hover:bg-white/5'}`}
                 >
                    <div className={`w-6 h-6 rounded-md ${space.color} flex items-center justify-center text-[10px] text-white font-bold shadow-sm`}>{space.icon}</div>
                    <span className="text-sm font-medium truncate flex-1">{space.name}</span>
                    {viewMode === 'SPACE' && activeSpaceId === space.id && <div className="w-1.5 h-1.5 bg-cofound-blue rounded-full"></div>}
                 </div>
              ))}
           </div>

           {/* DM SECTION */}
           <div className="pt-2">
              <div className="px-4 flex justify-between items-center mb-2">
                 <span className="text-xs font-bold text-cofound-textLight dark:text-cofound-textDark/50 uppercase tracking-widest">Direct Messages</span>
              </div>
              {CHAT_THREADS.map(thread => (
                <div 
                   key={thread.id} 
                   onClick={() => handleThreadSelect(thread)}
                   className={`px-4 py-2 mx-2 rounded-lg cursor-pointer flex items-center gap-3 transition-colors ${viewMode === 'DM' && selectedThread.id === thread.id ? 'bg-blue-50/50 dark:bg-white/10' : 'hover:bg-cofound-bg dark:hover:bg-white/5'}`}
                >
                   <div className="relative">
                      {thread.participants && thread.participants.length > 0 ? (
                        <div className="w-8 h-8 flex items-center justify-center bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-300 rounded-full font-bold text-xs ring-2 ring-white dark:ring-cofound-darkCard">
                           {thread.participants.length}
                        </div>
                      ) : (
                        <Avatar initials={thread.avatar} size="xs" />
                      )}
                      {!thread.participants && <div className={`absolute -bottom-0.5 -right-0.5 w-2 h-2 border border-white dark:border-cofound-darkCard rounded-full ${thread.status === 'online' ? 'bg-emerald-500' : 'bg-slate-300'}`}></div>}
                   </div>
                   <div className="flex-1 min-w-0">
