        </div>
      </div>

      {/* 2. MAIN CONTENT AREA (Switchable) */}
      <div className={`flex-1 flex-col relative bg-cofound-bg/10 dark:bg-black/20 ${showMobileChat ? 'flex' : 'hidden md:flex'}`}>

