              <div className="flex items-center gap-3">
                 <button onClick={() => setShowMobileChat(false)} className="md:hidden text-cofound-textLight dark:text-cofound-textDark/60 hover:text-cofound-text">
                    <ArrowLeft size={20} />
                 </button>
                 <div className="relative">
                    {selectedThread.participants ? (
                        <div className="w-10 h-10 flex items-center justify-center bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-300 rounded-full font-bold text-sm">
                           {selectedThread.participants.length}
                        </div>
                    ) : (
                        <Avatar initials={selectedThread.avatar} size="sm" />
                    )}
                 </div>
                 <div>
                    <h3 className="font-bold text-sm text-cofound-text dark:text-white">{selectedThread.user}</h3>
