                 </div>
              </div>
              <div className="flex items-center gap-2">
                 <Button variant="ghost" size="sm" className="hidden md:flex"><Phone size={16}/></Button>
                 <Button variant="ghost" size="sm" className="hidden md:flex"><Video size={16}/></Button>
