           <div className="h-auto md:h-16 border-b border-cofound-nav dark:border-white/10 flex flex-col md:flex-row md:items-center justify-between px-4 md:px-6 bg-white dark:bg-cofound-darkCard shrink-0">
              <div className="flex items-center gap-3 py-3 md:py-0">
                 <button onClick={() => setShowMobileChat(false)} className="md:hidden text-cofound-textLight dark:text-cofound-textDark/60 hover:text-cofound-text">
                    <ArrowLeft size={20} />
                 </button>
                 <div className={`w-8 h-8 rounded-lg ${activeSpace.color} flex items-center justify-center text-white font-bold shadow-sm`}>{activeSpace.icon}</div>
                 <div>
                    <h3 className="font-bold text-base text-cofound-text dark:text-white flex items-center gap-2">
