              <div className="flex gap-1 overflow-x-auto no-scrollbar pb-2 md:pb-0">
                 {activeSpace.channels.map(channel => {
                    const Icon = channel.type === 'CHAT' ? MessageSquare : channel.type === 'TASKS' ? CheckSquare : channel.type === 'NOTES' ? FileText : channel.type === 'FILES' ? Folder : Users;
                    return (
                       <button
                          key={channel.id}
                          onClick={() => setActiveChannel(channel)}
