import React, { useState, useEffect, useRef } from 'react';
import { 
  Plus, Search, Phone, Video, MoreHorizontal, Info, Mic, Send, Paperclip, 
  Hash, CheckSquare, FileText, Users, Folder, MessageSquare, ChevronDown, 
  ArrowLeft, Copy, Trash2, CornerUpRight, Flag, Smile
} from 'lucide-react';
import { Card, Avatar, Button, Chip } from '../components/UI';
import { CHAT_THREADS, MOCK_MESSAGES, SPACES, MOCK_TASKS, SQUAD_SUGGESTIONS } from '../data';
import { ChatThread, Message, Space, SpaceChannel, Task } from '../types';

interface ContextMenuState {
  visible: boolean;
  x: number;
  y: number;
  messageId: number | null;
  isMobile: boolean;
}

const Chat: React.FC = () => {
  // Navigation State
  const [viewMode, setViewMode] = useState<'DM' | 'SPACE'>('DM');
  const [showMobileChat, setShowMobileChat] = useState(false);

  // DM State
  const [selectedThread, setSelectedThread] = useState<ChatThread>(CHAT_THREADS[0]);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState("");
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Context Menu State
  const [contextMenu, setContextMenu] = useState<ContextMenuState>({
    visible: false,
    x: 0,
    y: 0,
    messageId: null,
    isMobile: false
  });
  const longPressTimer = useRef<NodeJS.Timeout | null>(null);

  // Space State
  const [spaces, setSpaces] = useState<Space[]>(SPACES);
  const [activeSpaceId, setActiveSpaceId] = useState<number>(SPACES[0].id);
  const [activeChannel, setActiveChannel] = useState<SpaceChannel>(SPACES[0].channels[0]);
  const [newSpaceName, setNewSpaceName] = useState("");
  const [showNewSpaceInput, setShowNewSpaceInput] = useState(false);

  // Derived
  const activeSpace = spaces.find(s => s.id === activeSpaceId) || spaces[0];

  // Load messages when thread changes
  useEffect(() => {
    const threadMessages = MOCK_MESSAGES[selectedThread.id] || [];
    setMessages(threadMessages);
  }, [selectedThread]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, activeChannel]); 

  // Close context menu on click outside or scroll
  useEffect(() => {
    const closeMenu = () => setContextMenu(prev => ({ ...prev, visible: false }));
    window.addEventListener('click', closeMenu);
    window.addEventListener('scroll', closeMenu, true);
    return () => {
      window.removeEventListener('click', closeMenu);
      window.removeEventListener('scroll', closeMenu, true);
    };
  }, []);

  const sendMessage = () => {
    if (!inputText.trim()) return;
    setMessages(prev => [...prev, { 
      id: prev.length + 100, 
      sender: "me", 
      text: inputText, 
      time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
    }]);
    setInputText("");
  };

  const handleCreateSpace = () => {
    if(!newSpaceName.trim()) return;
    const newSpace: Space = {
      id: Date.now(),
      name: newSpaceName,
      description: "New workspace",
      icon: newSpaceName[0].toUpperCase(),
      color: "bg-cofound-blue",
      members: 1,
      channels: [
        { id: `c-${Date.now()}-1`, name: "general", type: "CHAT" },
        { id: `c-${Date.now()}-2`, name: "tasks", type: "TASKS" }
      ]
    };
    setSpaces([...spaces, newSpace]);
    setNewSpaceName("");
    setShowNewSpaceInput(false);
    setActiveSpaceId(newSpace.id);
    setViewMode('SPACE');
    setShowMobileChat(true);
  };

  const handleThreadSelect = (thread: ChatThread) => {
    setViewMode('DM');
    setSelectedThread(thread);
    setShowMobileChat(true);
  };

  const handleSpaceSelect = (space: Space) => {
    setViewMode('SPACE');
    setActiveSpaceId(space.id);
    setActiveChannel(space.channels[0]);
    setShowMobileChat(true);
  };

  // --- CONTEXT MENU HANDLERS ---

  const handleContextMenu = (e: React.MouseEvent, msgId: number) => {
    e.preventDefault();
    setContextMenu({
      visible: true,
      x: e.clientX,
      y: e.clientY,
      messageId: msgId,
      isMobile: false
    });
  };

  const handleTouchStart = (msgId: number, e: React.TouchEvent) => {
    const touch = e.touches[0];
    const clientX = touch.clientX;
    const clientY = touch.clientY;

    longPressTimer.current = setTimeout(() => {
      // Vibrate if supported
      if (navigator.vibrate) navigator.vibrate(50);

      setContextMenu({
        visible: true,
        x: clientX,
        y: clientY,
        messageId: msgId,
        isMobile: true
      });
    }, 500); // 500ms long press
  };

  const handleTouchEnd = () => {
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }
  };

  const handleMenuAction = (action: string) => {
    console.log(`Action: ${action} on message ${contextMenu.messageId}`);
    setContextMenu(prev => ({ ...prev, visible: false }));
    // Here you would implement the actual logic (copy, delete, etc.)
  };

  const renderContextMenu = () => {
    if (!contextMenu.visible) return null;

    // Calculate position adjustments to keep menu on screen
    const menuWidth = 220; // Approx width
    const menuHeight = 250; // Approx height

    let left = contextMenu.x;
    let top = contextMenu.y;

    // Adjust horizontal position
    if (left + menuWidth > window.innerWidth) {
      left = window.innerWidth - menuWidth - 10;
    }

    // Adjust vertical position
    if (top + menuHeight > window.innerHeight) {
      top = window.innerHeight - menuHeight - 10;
    }

    // For mobile, we center it visually or use bottom sheet style, but simple positioning works for now
    // If mobile, we might want to offset it slightly up so finger doesn't cover it
    if (contextMenu.isMobile) {
       top -= 20; 
    }

    return (
      <div 
        className="fixed z-50 bg-white dark:bg-cofound-darkCard border border-cofound-grey/50 dark:border-white/10 rounded-xl shadow-2xl animate-fade-in overflow-hidden w-56 backdrop-blur-sm bg-opacity-95 dark:bg-opacity-95"
        style={{ left, top }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Emoji Reactions */}
        <div className="flex justify-between items-center p-2 bg-cofound-bg/50 dark:bg-white/5 border-b border-cofound-grey/50 dark:border-white/10">
           {['😊', '😢', '😂', '❤️', '😡'].map(emoji => (
             <button 
               key={emoji}
               onClick={() => handleMenuAction(`react-${emoji}`)}
               className="w-8 h-8 flex items-center justify-center text-lg hover:bg-white dark:hover:bg-white/10 rounded-full transition-transform hover:scale-125"
             >
               {emoji}
             </button>
           ))}
        </div>

        {/* Actions */}
        <div className="py-1">
           <button onClick={() => handleMenuAction('copy')} className="w-full text-left px-4 py-2.5 hover:bg-cofound-bg dark:hover:bg-white/5 flex items-center gap-3 text-sm font-medium text-cofound-text dark:text-white transition-colors">
              <Copy size={16} className="text-cofound-textLight dark:text-cofound-textDark/60" /> Copy Message
           </button>
           <button onClick={() => handleMenuAction('forward')} className="w-full text-left px-4 py-2.5 hover:bg-cofound-bg dark:hover:bg-white/5 flex items-center gap-3 text-sm font-medium text-cofound-text dark:text-white transition-colors">
              <CornerUpRight size={16} className="text-cofound-textLight dark:text-cofound-textDark/60" /> Forward
           </button>
           <div className="h-px bg-cofound-grey/50 dark:bg-white/10 my-1 mx-2"></div>
           <button onClick={() => handleMenuAction('report')} className="w-full text-left px-4 py-2.5 hover:bg-cofound-bg dark:hover:bg-white/5 flex items-center gap-3 text-sm font-medium text-cofound-text dark:text-white transition-colors">
              <Flag size={16} className="text-cofound-textLight dark:text-cofound-textDark/60" /> Report
           </button>
           <button onClick={() => handleMenuAction('delete')} className="w-full text-left px-4 py-2.5 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-3 text-sm font-medium text-red-600 dark:text-red-400 transition-colors">
              <Trash2 size={16} /> Delete
           </button>
        </div>
      </div>
    );
  };

  const renderChannelContent = () => {
    switch (activeChannel.type) {
      case 'TASKS':
        return (
          <div className="p-6 h-full overflow-y-auto pb-24 md:pb-6">
             <div className="flex justify-between items-center mb-6">
                <h3 className="font-bold text-lg text-cofound-text dark:text-white">Active Tasks</h3>
                <Button size="sm" variant="outline"><Plus size={16}/> Add Task</Button>
             </div>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {['TODO', 'IN_PROGRESS', 'DONE'].map(status => (
                   <div key={status} className="space-y-3">
                      <div className="flex items-center justify-between text-xs font-bold text-cofound-textLight dark:text-cofound-textDark/60 uppercase tracking-widest mb-2">
                         {status.replace('_', ' ')}
                         <span className="bg-cofound-grey dark:bg-white/10 px-2 py-0.5 rounded-full">{MOCK_TASKS.filter(t => t.status === status).length}</span>
                      </div>
                      {MOCK_TASKS.filter(t => t.status === status).map(task => (
                         <div key={task.id} className="bg-white dark:bg-cofound-darkCard p-3 rounded-xl border border-cofound-grey dark:border-white/10 shadow-sm hover:shadow-md transition-shadow cursor-pointer group">
                            <div className="flex justify-between items-start mb-2">
                               <span className={`text-[10px] px-1.5 py-0.5 rounded font-bold ${task.tag === 'Backend' ? 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300' : 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300'}`}>{task.tag}</span>
                               <MoreHorizontal size={14} className="text-cofound-textLight dark:text-cofound-textDark/40 opacity-0 group-hover:opacity-100 transition-opacity"/>
                            </div>
                            <p className="text-sm font-medium text-cofound-text dark:text-white mb-3">{task.title}</p>
                            <div className="flex items-center justify-between">
                               <Avatar initials={task.assignee} size="xs" />
                               <div className="text-[10px] text-cofound-textLight dark:text-cofound-textDark/50">Oct 24</div>
                            </div>
                         </div>
                      ))}
                      <button className="w-full py-2 border border-dashed border-cofound-grey dark:border-white/10 rounded-xl text-xs font-bold text-cofound-textLight dark:text-cofound-textDark/50 hover:bg-cofound-bg dark:hover:bg-white/5 transition-colors">
                         + New
                      </button>
                   </div>
                ))}
             </div>
          </div>
        );
      case 'NOTES':
        return (
          <div className="p-8 h-full flex flex-col items-center justify-center text-center opacity-60">
             <FileText size={48} className="mb-4 text-cofound-textLight dark:text-cofound-textDark/40" />
             <h3 className="font-bold text-lg text-cofound-text dark:text-white">Team Notes</h3>
             <p className="text-sm max-w-xs text-cofound-textLight dark:text-cofound-textDark/60 mt-1">Shared documents and meeting minutes live here.</p>
             <Button variant="primary" size="sm" className="mt-4">Create Doc</Button>
          </div>
        );
      case 'FILES':
        return (
          <div className="p-6 h-full overflow-y-auto">
             <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {[1,2,3,4].map(i => (
                   <div key={i} className="aspect-square bg-white dark:bg-cofound-darkCard rounded-xl border border-cofound-grey dark:border-white/10 flex flex-col items-center justify-center p-4 hover:border-cofound-blue/50 cursor-pointer transition-colors">
                      <Folder size={32} className="text-cofound-blue dark:text-cofound-sky mb-2 fill-current opacity-20" />
                      <span className="text-sm font-bold text-cofound-text dark:text-white truncate w-full text-center">Design_Assets_v{i}.zip</span>
