      case 'MEMBERS':
        return (
           <div className="p-6">
              <h3 className="font-bold text-lg mb-4 text-cofound-text dark:text-white">Space Members ({activeSpace.members})</h3>
              <div className="space-y-2">
                 {SQUAD_SUGGESTIONS.slice(0, activeSpace.members).map(member => (
                    <div key={member.id} className="flex items-center justify-between p-3 bg-white dark:bg-cofound-darkCard rounded-xl border border-cofound-grey dark:border-white/10">
                       <div className="flex items-center gap-3">
                          <Avatar initials={member.name.substring(0,2)} size="md" />
                          <div>
                             <div className="font-bold text-sm text-cofound-text dark:text-white">{member.name}</div>
                             <div className="text-xs text-cofound-textLight dark:text-cofound-textDark/60">{member.role}</div>
                          </div>
                       </div>
                       <Button variant="ghost" size="sm">Message</Button>
                    </div>
                 ))}
              </div>
           </div>
        );
      case 'CHAT':
      default:
        // Reuse the chat layout for consistency
        return (
          <div className="flex flex-col h-full bg-cofound-bg/10 dark:bg-black/20">
             <div className="flex-1 p-4 md:p-6 overflow-y-auto space-y-4">
                <div className="flex justify-center pb-4">
                   <span className="text-xs font-bold text-cofound-textLight dark:text-cofound-textDark/40 uppercase tracking-widest bg-cofound-bg dark:bg-white/5 px-3 py-1 rounded-full"># {activeChannel.name} history</span>
                </div>
                {messages.map(msg => (
                  <div key={msg.id} className={`flex ${msg.sender === 'me' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[85%] md:max-w-[70%] ${msg.sender === 'me' ? 'items-end' : 'items-start'} flex flex-col`}>
                        <div 
                            onContextMenu={(e) => handleContextMenu(e, msg.id)}
                            onTouchStart={(e) => handleTouchStart(msg.id, e)}
                            onTouchEnd={handleTouchEnd}
                            onTouchMove={handleTouchEnd}
                            className={`px-4 py-2.5 rounded-2xl text-sm leading-relaxed shadow-sm relative group cursor-pointer transition-transform active:scale-[0.98] ${
                            msg.sender === 'me' 
                              ? 'bg-cofound-blue text-white rounded-br-none' 
                              : 'bg-white dark:bg-cofound-darkCard border border-cofound-nav dark:border-white/10 text-cofound-text dark:text-cofound-textDark rounded-bl-none'
                        }`}>
                            {msg.text}
                        </div>
                        <span className="text-[10px] text-cofound-textLight dark:text-cofound-textDark/40 mt-1 px-1 opacity-70">{msg.time}</span>
                      </div>
                  </div>
                ))}
                <div ref={messagesEndRef} />
             </div>
             {/* Input Area */}
             <div className="p-3 md:p-4 bg-white dark:bg-cofound-darkCard border-t border-cofound-nav dark:border-white/10 shrink-0 pb-4 md:pb-4">
                <div className="flex items-end gap-2">
                    <button className="p-2.5 text-cofound-textLight dark:text-cofound-textDark/60 hover:text-cofound-blue hover:bg-blue-50 dark:hover:bg-white/5 rounded-full transition-colors mb-0.5"><Plus size={20} /></button>
                    <div className="flex-1 bg-cofound-bg dark:bg-white/5 rounded-2xl p-2 flex items-center gap-2 border border-transparent focus-within:border-cofound-blue/30 focus-within:bg-white dark:focus-within:bg-black/20 transition-all">
                      <input 
                          type="text"
                          value={inputText}
                          onChange={(e) => setInputText(e.target.value)}
                          onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), sendMessage())}
                          placeholder={`Message #${activeChannel.name}`}
                          className="flex-1 bg-transparent border-none outline-none text-sm text-cofound-text dark:text-white placeholder:text-cofound-textLight/70 dark:placeholder:text-white/30 px-2"
                      />
                      <button className="p-1.5 text-cofound-textLight dark:text-cofound-textDark/50 hover:text-cofound-blue transition-colors"><Paperclip size={18} /></button>
                    </div>
                    <Button 
                      onClick={sendMessage}
                      size="md"
                      variant={inputText.trim() ? "primary" : "secondary"}
                      className={`!p-2.5 rounded-full mb-0.5 transition-all`}
                      disabled={!inputText.trim()}
                    >
                      <Send size={18} className={inputText.trim() ? "ml-0.5" : ""} />
                    </Button>
                </div>
             </div>
          </div>
        );
    }
  };

  return (
    <Card className="flex-1 md:h-[calc(100vh-120px)] flex flex-row !p-0 overflow-hidden shadow-lg border-cofound-nav dark:border-white/10 border-0 rounded-none md:rounded-2xl h-full">
      {renderContextMenu()}

      {/* 1. UNIFIED SIDEBAR (Spaces + DMs) */}
      <div className={`w-full md:w-80 border-r border-cofound-nav dark:border-white/10 flex flex-col bg-white dark:bg-cofound-darkCard ${showMobileChat ? 'hidden md:flex' : 'flex'}`}>

        {/* Search Header */}
        <div className="p-4 border-b border-cofound-nav dark:border-white/10 bg-cofound-bg/30 dark:bg-white/5 space-y-3">
           <div className="flex justify-between items-center">
              <h2 className="font-bold text-lg text-cofound-text dark:text-white">Comms</h2>
              <button className="p-1.5 hover:bg-cofound-grey dark:hover:bg-white/10 rounded-full transition-colors text-cofound-textLight dark:text-cofound-textDark/60"><MoreHorizontal size={18}/></button>
           </div>
           <div className="relative">
              <Search className="absolute left-3 top-2.5 text-cofound-textLight dark:text-cofound-textDark/50" size={14} />
              <input type="text" placeholder="Jump to..." className="w-full bg-cofound-bg dark:bg-white/5 pl-9 pr-3 py-2 rounded-lg text-sm outline-none focus:ring-1 focus:ring-cofound-blue dark:text-white transition-all" />
           </div>
        </div>

        <div className="flex-1 overflow-y-auto no-scrollbar">

           {/* SPACES SECTION */}
           <div className="pt-4 pb-2">
              <div className="px-4 flex justify-between items-center mb-2 group">
                 <span className="text-xs font-bold text-cofound-textLight dark:text-cofound-textDark/50 uppercase tracking-widest">My Spaces</span>
                 <button onClick={() => setShowNewSpaceInput(!showNewSpaceInput)} className="text-cofound-textLight dark:text-cofound-textDark/50 hover:text-cofound-blue"><Plus size={14} /></button>
              </div>

              {showNewSpaceInput && (
                 <div className="px-4 mb-2 animate-fade-in">
                    <input 
                      autoFocus
                      type="text" 
                      placeholder="Space name..." 
                      className="w-full text-sm bg-cofound-bg dark:bg-white/5 px-2 py-1.5 rounded border border-cofound-blue/30 outline-none text-cofound-text dark:text-white"
                      value={newSpaceName}
                      onChange={(e) => setNewSpaceName(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && handleCreateSpace()}
                    />
                 </div>
              )}

              {spaces.map(space => (
                 <div 
                    key={space.id} 
                    onClick={() => handleSpaceSelect(space)}
                    className={`px-4 py-2 mx-2 rounded-lg cursor-pointer flex items-center gap-3 transition-colors ${viewMode === 'SPACE' && activeSpaceId === space.id ? 'bg-blue-50/50 dark:bg-white/10 text-cofound-text dark:text-white' : 'text-cofound-textLight dark:text-cofound-textDark/70 hover:bg-cofound-bg dark:hover:bg-white/5'}`}
                 >
                    <div className={`w-6 h-6 rounded-md ${space.color} flex items-center justify-center text-[10px] text-white font-bold shadow-sm`}>{space.icon}</div>
                    <span className="text-sm font-medium truncate flex-1">{space.name}</span>
                    {viewMode === 'SPACE' && activeSpaceId === space.id && <div className="w-1.5 h-1.5 bg-cofound-blue rounded-full"></div>}
                 </div>
