                <div 
                   key={thread.id} 
                   onClick={() => handleThreadSelect(thread)}
                   className={`px-4 py-2 mx-2 rounded-lg cursor-pointer flex items-center gap-3 transition-colors ${viewMode === 'DM' && selectedThread.id === thread.id ? 'bg-blue-50/50 dark:bg-white/10' : 'hover:bg-cofound-bg dark:hover:bg-white/5'}`}
